// // This is a 4-bit Johnson counter that counts down on each clock edge.
module johnson_counter_4bit (
    input wire clk,
    input wire rst,
    output reg [3:0] q
);

    always @(posedge clk) begin
        if (rst)
            q <= 4'b0000;
        else
            q <= {q[2:0], ~q[3]};
    end

endmodule
